          },
          "type": "document"
        }
      ],
      "purchaseMethod": {
        "type": "token"
      }
    }
  }
}
```

The following query searches the collection for items tagged `school`
with a preference for items named `backpack`. MongoDB Search scores the results
in descending order based on the average (arithmetic mean) score of all
matching embedded documents. The query includes a [$limit](manual/reference/operator/aggregation/limit)
stage to limit the output to `5` documents and a [$project](manual/reference/operator/aggregation/project)
stage to:

- Exclude all fields except `items.name` and `items.tags` fields

- Add a field named `score`

**Input:**

```json
db.sales.aggregate({
  "$search": {
    "embeddedDocument": {
      "path": "items",
      "operator": {
        "compound": {
          "must": [{
            "text": {
              "path": "items.tags",
              "query": "school"
            }
          }],
          "should": [{
            "text": {
              "path": "items.name",
              "query": "backpack"
            }
          }]
        }
      },
      "score": {
        "embedded": {
          "aggregate": "mean"
        }
      }
    }
  }
},
{
  $limit: 5
},
{
  $project: {
    "_id": 0,
    "items.name": 1,
    "items.tags": 1,
    "score": { $meta: "searchScore" }
  }
})
```

